package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract representation of a node in a domain tree; defines methods for getting
 * domains, child nodes, and generating values.
 */
public abstract class APyNode {

    /**
     * Returns the left child of this node.
     *
     * @return the left child of this node, or null if this is a leaf node
     */
    public abstract APyNode getLeftChild();

    /**
     * Returns the right child of this node.
     *
     * @return the right child of this node, or null if this is a leaf node
     */
    public abstract APyNode getRightChild();

    /**
     * Returns all values in the extensive domain as a set of Python objects.
     *
     * @return all values in the extensive domain
     */
    public abstract <T extends APyObj> Set<T> genExVals();

    /**
     * Returns a random value from the random domain as a Python object.
     *
     * @return a random value from the random domain
     */
    public abstract <T extends APyObj> T genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * A representation of a node that generates PyBoolObj values from domains.
 * The domain consists of integers (0 for false, 1 for true).
 */
public class PyBoolNode extends APyNode {

    /**
     * The extensive domain: a list of integers (0 or 1) to be used in exhaustive testing.
     */
    private List<Integer> exDomain;

    /**
     * The random domain: a list of integers (0 or 1) to be used in random testing.
     */
    private List<Integer> ranDomain;

    /**
     * Random number generator for genRandVal.
     */
    private final Random random = new Random();

    /**
     * Constructor for a PyBoolNode; initializes domains to empty lists.
     */
    public PyBoolNode() {
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    /**
     * Sets the extensive domain for this node.
     *
     * @param exDomain the extensive domain (list of integers)
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the extensive domain for this node.
     *
     * @return the extensive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain (list of integers)
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns null since PyBoolNode is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode getLeftChild() {
        return null;
    }

    /**
     * Returns null since PyBoolNode is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode getRightChild() {
        return null;
    }

    /**
     * Generates all values in the extensive domain as PyBoolObj instances.
     * 0 maps to false, 1 maps to true.
     *
     * @return a set of PyBoolObj values
     */
    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            if (val == 0) {
                result.add(new PyBoolObj(false));
            } else if (val == 1) {
                result.add(new PyBoolObj(true));
            }
        }
        return result;
    }

    /**
     * Generates a random value from the random domain as a PyBoolObj.
     * 0 maps to false, 1 maps to true.
     *
     * @return a random PyBoolObj from the random domain
     */
    @Override
    public PyBoolObj genRandVal() {
        Integer val = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        return new PyBoolObj(val == 1);
    }
}

